fun loadDashboard() {
    viewModelScope.launch {
        supervisorScope {
            val feed = async { runCatching { api.getFeed() }.getOrNull() }
            val recommendations = async { runCatching { api.getRecommendations() }.getOrNull() }
            val trending = async { runCatching { api.getTrending() }.getOrNull() }

            _uiState.value = DashboardState(
                feed = feed.await(),
                recommendations = recommendations.await(),
                trending = trending.await()
            )
        }
    }
}

